    <script>
        const vn = "{{ $patientQueue['vn'] }}";
        
        // Auto update status every 15 seconds
        setInterval(() => {
            fetch(`/api/hosxp/queue/${vn}`)
                .then(res => res.json())
                .then(res => {
                    if (res.success) {
                        const data = res.data;
                        document.getElementById('my-queue').innerText = data.my_queue;
                        document.getElementById('dep-name').innerText = data.department_name;
                        document.getElementById('waiting-ahead').innerText = data.waiting_ahead;
                        document.getElementById('estimated-time').innerText = `${data.estimated_minutes} นาที`;
                        document.getElementById('updated-at').innerText = data.updated_at;
                    }
                })
                .catch(err => console.log('Auto update error:', err));
        }, 15000);
    </script>
